import{c as e,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"12 Agentic Harness Patterns from Claude Code","description":"","frontmatter":{"url":"https://medium.com/@simranjeetsingh1497/agent-harness-12-agentic-harness-patterns-from-claude-code-5505b7c239c4","title":"12 Agentic Harness Patterns from Claude Code","status":"RETRIEVED_FROM_ALTERNATIVE","alternative_urls":["https://generativeprogrammer.com/p/12-agentic-harness-patterns-from","https://www.epsilla.com/blogs/2026-04-18-deep-dive-12-reusable-agentic-harness-design-patte"],"date_retrieved":"2026-05-18T00:00:00.000Z","original_status":"URL_REDIRECT_FAIL"},"headers":[],"relativePath":"research/ai-articles/32-medium-12-agentic-harness-patterns.md","filePath":"research/ai-articles/32-medium-12-agentic-harness-patterns.md","lastUpdated":1779894392000}'),i={name:"research/ai-articles/32-medium-12-agentic-harness-patterns.md"};function n(s,t,l,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_12-agentic-harness-patterns-from-claude-code" tabindex="-1">12 Agentic Harness Patterns from Claude Code <a class="header-anchor" href="#_12-agentic-harness-patterns-from-claude-code" aria-label="Permalink to &quot;12 Agentic Harness Patterns from Claude Code&quot;">​</a></h1><h2 id="來源說明" tabindex="-1">來源說明 <a class="header-anchor" href="#來源說明" aria-label="Permalink to &quot;來源說明&quot;">​</a></h2><p>原始 Medium 文章需要登入。本文內容已從以下替代來源成功抓取：</p><ul><li><a href="https://generativeprogrammer.com/p/12-agentic-harness-patterns-from" target="_blank" rel="noreferrer">GenerativeProgrammer</a></li><li><a href="https://www.epsilla.com/blogs/2026-04-18-deep-dive-12-reusable-agentic-harness-design-patte" target="_blank" rel="noreferrer">Epsilla Engineering Blog</a></li></ul><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><p>Claude Code 的設計中發現了 12 個可重用的 Agentic Harness 模式，系統性地解決生產級 AI Agent 的四大關鍵領域：記憶與上下文、工作流程與編排、工具與權限、自動化。</p><p><strong>記憶與上下文（5 個模式）</strong> 的核心思路在於分層與動態加載。<code>Persistent Instruction File</code> 模式將架構規則與命名約定封裝於配置檔案中，在每次 session 開始時自動注入，消除用戶重複輸入。<code>Scoped Context Assembly</code> 在單體倉庫中動態載入特定目錄層級的指令，確保 Agent 看到與其工作環境相符的規則。<code>Tiered Memory</code> 透過分層策略保持高頻索引始終在上下文中，專題細節按需加載，完整日誌只供離線搜尋。<code>Dream Consolidation</code> 利用後台進程在閒置時定期去重複與剪除過時記憶，防止長期運行中的索引膨脹。<code>Progressive Context Compaction</code> 採用多級壓縮，近期交互保留完整細節，舊交互逐層摘要化，支持 20-30+ 輪交互。</p><p><strong>工作流程與編排（3 個模式）</strong> 強調階段隔離與並行處理。<code>Explore-Plan-Act Loop</code> 將工作分為唯讀研究、對齐規劃與代碼變更三個階段，權限逐級提升，防止基於不完整理解的倉促改動。<code>Context-Isolated Subagents</code> 為不同角色（研究者、規劃者、執行者）分配沙箱化上下文，實現任務特定的隔離與可控性。<code>Fork-Join Parallelism</code> 將工作分片至多個 Subagent，各自在隔離的倉庫副本中獨立運作，最後合併結果，實現並行執行。</p><p><strong>工具與權限（3 個模式）</strong> 實踐「最小權限原則」與可審計設計。<code>Progressive Tool Expansion</code> 默認使用不超過 20 個核心工具的最小集合，按需動態啟用專化工具，而非一次性暴露全工具庫。<code>Command Risk Classification</code> 在執行前以確定性的風險矩陣評估命令影響範圍，低風險操作自動批准，高風險操作閘門人工審批。<code>Single-Purpose Tool Design</code> 用特定、確定性的工具（如 FileReadTool、GrepTool）替代通用 Shell 包裝器，提升可審計性與認知負荷。</p><p><strong>自動化（1 個模式）</strong> 的關鍵在於確定性與非依賴 LLM 記憶。<code>Deterministic Lifecycle Hooks</code> 將非協商的操作綁定至 Agent 生命週期事件（25+ 個鉤子），通過中間件在提示外自動執行，確保程序步驟可靠執行，不依賴模型上下文合規性。</p><p>這 12 個模式構成了「Harness Engineering」的核心框架，與 Karpathy 的 4 條基礎規則及 Mnilax 的 8 條增量規則形成完整的 12-Rule Canon，實現從探索→規劃→執行的系統性 Agent 工程。</p><h2 id="_12-個模式清單" tabindex="-1">12 個模式清單 <a class="header-anchor" href="#_12-個模式清單" aria-label="Permalink to &quot;12 個模式清單&quot;">​</a></h2><h3 id="記憶與上下文" tabindex="-1">記憶與上下文 <a class="header-anchor" href="#記憶與上下文" aria-label="Permalink to &quot;記憶與上下文&quot;">​</a></h3><ol><li><strong>Persistent Instruction File</strong> — 配置檔案在 Session 啟動時自動注入，定義架構規則與命名約定</li><li><strong>Scoped Context Assembly</strong> — 指令按工作目錄動態加載，支持單體倉庫的分層規則</li><li><strong>Tiered Memory</strong> — 精簡索引常駐上下文，細節按需加載，完整日誌離線存儲</li><li><strong>Dream Consolidation</strong> — 背景進程定期去重複與剪除過時記憶，防止索引膨脹</li><li><strong>Progressive Context Compaction</strong> — 近期交互保留細節，舊交互逐層摘要化</li></ol><h3 id="工作流程與編排" tabindex="-1">工作流程與編排 <a class="header-anchor" href="#工作流程與編排" aria-label="Permalink to &quot;工作流程與編排&quot;">​</a></h3><ol start="6"><li><strong>Explore-Plan-Act Loop</strong> — 唯讀研究 → 規劃討論 → 代碼變更，權限逐級提升</li><li><strong>Context-Isolated Subagents</strong> — 角色特定的沙箱化上下文，防止工作階段污染</li><li><strong>Fork-Join Parallelism</strong> — 多 Subagent 並行工作，隔離倉庫副本，合併結果</li></ol><h3 id="工具與權限" tabindex="-1">工具與權限 <a class="header-anchor" href="#工具與權限" aria-label="Permalink to &quot;工具與權限&quot;">​</a></h3><ol start="9"><li><strong>Progressive Tool Expansion</strong> — 最小工具集（&lt;20）默認加載，專化工具按需啟用</li><li><strong>Command Risk Classification</strong> — 確定性風險評估，低風險自動批准，高風險人工審批</li><li><strong>Single-Purpose Tool Design</strong> — 特定工具替代通用 Shell，提升可審計性</li></ol><h3 id="自動化" tabindex="-1">自動化 <a class="header-anchor" href="#自動化" aria-label="Permalink to &quot;自動化&quot;">​</a></h3><ol start="12"><li><strong>Deterministic Lifecycle Hooks</strong> — 25+ 鉤子綁定生命週期事件，可靠執行程序步驟</li></ol><h2 id="關鍵引用" tabindex="-1">關鍵引用 <a class="header-anchor" href="#關鍵引用" aria-label="Permalink to &quot;關鍵引用&quot;">​</a></h2><h3 id="記憶與上下文層面" tabindex="-1">記憶與上下文層面 <a class="header-anchor" href="#記憶與上下文層面" aria-label="Permalink to &quot;記憶與上下文層面&quot;">​</a></h3><blockquote><p>&quot;A lean, high-level index remains persistently in the active context. Task-specific details are dynamically loaded on-demand&quot; while comprehensive logs stay on disk.</p></blockquote><p>這個設計體現了上下文預算的明智分配：高頻訪問的決策與狀態保持在 LLM 窗口中，低頻的歷史與細節卸載至磁盤，實現「主記憶」與「輔助儲存」的二級制。</p><h3 id="工作流程層面" tabindex="-1">工作流程層面 <a class="header-anchor" href="#工作流程層面" aria-label="Permalink to &quot;工作流程層面&quot;">​</a></h3><blockquote><p>&quot;Workflows separate into read-only research, alignment planning, and code mutation phases with escalating permissions.&quot;</p></blockquote><p>此模式直接對應 Karpathy Rule 1（Think Before Coding）與 Rule 3（Surgical Modifications）——先通過完全探索期減少盲目決策，再在規劃確認後才執行變更，從系統級層面強制「寧可謹慎也不倉促」的原則。</p><h3 id="工具與權限層面" tabindex="-1">工具與權限層面 <a class="header-anchor" href="#工具與權限層面" aria-label="Permalink to &quot;工具與權限層面&quot;">​</a></h3><blockquote><p>&quot;Middleware evaluates command blast radius against risk matrices, routing low-risk operations while gating high-risk actions for human approval.&quot;</p></blockquote><p>這是 Rule 5（Latent vs Deterministic 邊界）的工程實踐——風險評估這種確定性邏輯不交由 LLM，而由確定性代碼（中間件）負責，LLM 專注於「應該做什麼」，確定性層專注於「能否做」。</p><h2 id="與-karpathy-mnilax-規則的關聯" tabindex="-1">與 Karpathy/Mnilax 規則的關聯 <a class="header-anchor" href="#與-karpathy-mnilax-規則的關聯" aria-label="Permalink to &quot;與 Karpathy/Mnilax 規則的關聯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>規則</th><th>對應模式</th><th>工程實踐</th></tr></thead><tbody><tr><td>R1 — Think Before Coding</td><td>Explore-Plan-Act Loop</td><td>強制唯讀探索期，延遲決策</td></tr><tr><td>R2 — Simplicity First</td><td>Progressive Tool Expansion</td><td>最小工具集默認，杜絕工具過載</td></tr><tr><td>R3 — Surgical Modifications</td><td>Context-Isolated Subagents</td><td>隔離階段，防止副作用污染</td></tr><tr><td>R4 — Goal-Oriented</td><td>Deterministic Lifecycle Hooks</td><td>可觀測的生命週期檢查點</td></tr><tr><td>R5 — Latent vs Deterministic</td><td>Command Risk Classification</td><td>風險評估交由確定性層</td></tr><tr><td>R6 — Context Budget</td><td>Tiered Memory</td><td>主記憶精簡，按需加載</td></tr><tr><td>R7 — Surface Conflicts</td><td>Scoped Context Assembly</td><td>動態加載，暴露衝突</td></tr><tr><td>R8 — Read Before Write</td><td>Progressive Compaction</td><td>完整日誌保留，按需讀取</td></tr><tr><td>R9 — Test Intent</td><td>Deterministic Lifecycle Hooks</td><td>鉤子層驗證業務邏輯</td></tr><tr><td>R10 — Checkpoint</td><td>Progressive Context Compaction</td><td>定期檢查點，防止上下文漂移</td></tr><tr><td>R11 — Convention First</td><td>Persistent Instruction File</td><td>架構規則中央化，自動加載</td></tr><tr><td>R12 — Fail Loud</td><td>Deterministic Lifecycle Hooks</td><td>鉤子層確保容錯可觀測</td></tr></tbody></table><h2 id="實踐路徑" tabindex="-1">實踐路徑 <a class="header-anchor" href="#實踐路徑" aria-label="Permalink to &quot;實踐路徑&quot;">​</a></h2><ol><li><strong>Foundation</strong>（基礎）：實現 Persistent Instruction File + Explore-Plan-Act Loop</li><li><strong>Scale</strong>（擴展）：加入 Tiered Memory + Progressive Tool Expansion</li><li><strong>Robustness</strong>（穩定性）：部署 Deterministic Lifecycle Hooks + Command Risk Classification</li><li><strong>Optimization</strong>（最佳化）：調整 Dream Consolidation + Progressive Context Compaction</li></ol><p>此順序遵循「核心優先，邊界邊界清晰，自動化最後」的原則，確保每一層都能獨立驗證。</p><hr><p><strong>抓取來源驗證</strong>：</p><ul><li>generativeprogrammer.com — 完整文章，12 個模式清晰分類（2026-05-18 快取驗證）</li><li>epsilla.com — 深度解析，工程實踐細節補充（2026-05-18 快取驗證）</li></ul>',38)])])}const m=e(i,[["render",n]]);export{p as __pageData,m as default};
